import { objectValues } from '../../utils/zcutils';

export function getGridList(processor) {
    let pivotLayout = processor.hierarchical.pivotLayout,
        layers = pivotLayout.getRootNodeList('layer'),
        panes = layers.panes;

    return objectValues(panes);
}

export function getCurrentRendererIndex(panes, paneIndex) {
    let rendererIdx = 0,
        arr = objectValues(panes);

    for (let i = 0; i < paneIndex; i++) {
        let currentPaneIndex = arr[i].index === i ? i : arr.filter(d => d.index === i)[0];
        rendererIdx += arr[currentPaneIndex].data.length;
    }

    return rendererIdx;
}
